UPDATE DatiCollezioniPerImport INNER JOIN Item ON DatiCollezioniPerImport.[BRIDGE STYLE CODE] = Item.No_ SET Item.[Gross Weight] = [lordo], Item.Height = [Shoebox height (cm)], Item.Width = [Shoebox width (cm)], Item.Depth = [Shoebox lenght (cm)], Item.[Upper Composition] = [Composizione Tomaia], Item.[Upper Composition For Duty] = [COMPOSIZIONE TOMAIA PER DOGANA], Item.[Lining Composition] = [Composizione Fodera], Item.[Insole Composition] = [Composizione Sottopiede], Item.[Outsole Composition] = [Composizione Suola], Item.[Tariff No_] = [tariff nr], Item.[Net Weight] = [Net weight (kg)], Item.[Unit Volume] = [Volume (m3)], Item.duty = Format$([Duty %],"Percent");

